-- Migration: certifications gain MULTIPLE categories (category -> categories[]),
-- plus more Software Engineering & Data Science certs. Idempotent upsert.
--   psql -h 127.0.0.1 -p 5433 -U cotailor -d cotailor -f apps/api/prisma/cert-catalog-multicat.sql

ALTER TABLE "CertificationCatalog" ADD COLUMN IF NOT EXISTS "categories" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[];
DROP INDEX IF EXISTS "CertificationCatalog_category_idx";
ALTER TABLE "CertificationCatalog" DROP COLUMN IF EXISTS "category";

-- Full upsert: fixes existing rows' categories/subtypes (incl. the cross-over ML
-- certs) and inserts the new ones. Re-runnable.
ON CONFLICT ("id") DO UPDATE SET
  name = EXCLUDED.name, issuer = EXCLUDED.issuer, level = EXCLUDED.level,
  categories = EXCLUDED.categories, subtypes = EXCLUDED.subtypes, aliases = EXCLUDED.aliases;
